// MinimockFinish checks that all mocked methods have been called the expected number of times
func (m *UserMock) MinimockFinish() {
	m.finishOnce.Do(func() {
		if !m.minimockDone() {
			m.MinimockCreateInspect()

			m.MinimockDeactivateInspect()

			m.MinimockGetByEmailInspect()

			m.MinimockGetByIDInspect()

			m.MinimockListByAccountInspect()

			m.MinimockReactivateInspect()

			m.MinimockUpdateInspect()
		}
	})
}

// MinimockWait waits for all mocked methods to be called the expected number of times
func (m *UserMock) MinimockWait(timeout mm_time.Duration) {
	timeoutCh := mm_time.After(timeout)
	for {
		if m.minimockDone() {
			return
		}
		select {
		case <-timeoutCh:
			m.MinimockFinish()
			return
		case <-mm_time.After(10 * mm_time.Millisecond):
		}
	}
}

func (m *UserMock) minimockDone() bool {
	done := true
	return done &&
		m.MinimockCreateDone() &&
		m.MinimockDeactivateDone() &&
		m.MinimockGetByEmailDone() &&
		m.MinimockGetByIDDone() &&
		m.MinimockListByAccountDone() &&
		m.MinimockReactivateDone() &&
		m.MinimockUpdateDone()
}
